<link rel='stylesheet' href='https://cdn.jsdelivr.net/npm/swiper@11/swiper-bundle.min.css'>
<style>
    .section-title {
        color: var(--primary-text);
        text-align: center;
        font-size: 40px;
        font-family: "Cormorant Garamond";
        font-weight: bold;
        font-style: normal;
        line-height: 48px;
        position: relative;
        margin-bottom: 52px;
    }

    .section-title::before,
    .section-title::after {
        content: "";
        position: absolute;
        left: 25%;
        top: 22px;
        width: 45px;
        height: 2px;
        background-color: var(--secondary-text);
    }

    .section-title::after {
        left: unset;
        right: 25%;
    }

    .testimonial-section {
        padding-top: 32px;
        padding-bottom: 22px;
    }

    .swiper {
        width: 100%;
        height: 100%;
        margin-left: auto;
        margin-right: auto;
    }

    .swiper-slide {
        text-align: center;
        border-radius: 40px;
        padding: 30px 23px;
        background: var(--primary-text);
        display: flex;
        justify-content: center;
        align-items: center;
        flex-direction: column;
        width: auto !important;
        height: 100% !important;
    }

    .swiper-slide img {
        display: block;
        width: 100%;
        height: 100%;
        object-fit: cover;
    }

    .swiper-pagination-bullet {
        width: var(--swiper-pagination-bullet-width,
                var(--swiper-pagination-bullet-size, 15px));
        height: var(--swiper-pagination-bullet-height,
                var(--swiper-pagination-bullet-size, 15px));
        background: #d9d9d9;
        background: #504b4b;
    }

    .swiper-horizontal>.swiper-pagination-bullets,
    .swiper-pagination-bullets.swiper-pagination-horizontal,
    .swiper-pagination-custom,
    .swiper-pagination-fraction {
        bottom: var(--swiper-pagination-bottom, -4px);
    }

    .swiper-pagination-bullet-active {
        background: var(--primary-text);
    }

    .swiper.testimonial-wrapper {
        padding-top: 59px;
        padding-bottom: 60px;
    }

    .testimonial-items .testimonial-text {
        color: var(--white-text-white);
        text-align: center;
        font-size: 16px;
        font-family: "Outfit";
        font-weight: normal;
        font-style: normal;
        max-width: 330px;
        margin-bottom: 45px;
        overflow: hidden;
        display: -webkit-box;
        -webkit-box-orient: vertical;
        line-clamp: 4;
        -webkit-line-clamp: 4;
    }

    .testimonial-items .testimonial-title {
        color: var(--white-text-white);
        text-align: center;
        font-size: 16px;
        font-family: "Outfit";
        font-weight: bold;
        font-style: normal;
        margin-bottom: 35px;
        position: relative;
    }

    .testimonial-items .testimonial-title::before {
        content: "";
        position: absolute;
        left: -23px;
        top: 9px;
        width: 20px;
        height: 1px;
        background-color: var(--white-text-white);
    }

    .testimonial-img {
        position: relative;
        width: 100px;
        height: 100px;
        height: 70px;
    }

    .testimonial-img::before {
        content: "";
        position: absolute;
        left: 50%;
        top: -50%;
        transform: translate(-50%, -50%);
        width: 100px;
        height: 100px;
        border-radius: 50%;
        background-repeat: no-repeat;
        background-position: center;
        background-size: cover;
    }

    .testimonial-img.tm-img-1::before {
        background-image: url(https://w7.pngwing.com/pngs/646/829/png-transparent-avatar-man-ico-icon-cartoon-little-boy-avatar-cartoon-character-png-material-child-thumbnail.png);
    }

    .testimonial-img.tm-img-2::before {
        background-image: url(https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcS2IYhSn8Y9S9_HF3tVaYOepJBcrYcd809pBA&s);
    }

    .testimonial-img.tm-img-3::before {
        background-image: url(https://png.pngtree.com/element_our/png/20181206/female-avatar-vector-icon-png_262142.jpg);
    }

    /* media query  */
    @media screen and (min-width: 768px) {
        .swiper-pagination-bullet {
            width: var(--swiper-pagination-bullet-width,
                    var(--swiper-pagination-bullet-size, 24px));
            height: var(--swiper-pagination-bullet-height,
                    var(--swiper-pagination-bullet-size, 24px));
        }

        .section-title::before,
        .section-title::after {
            width: 141px;
        }

        /*   .section-title::before,
  .section-title::after {
    left: 25%;
  }
  .section-title::after {
    right: 25%;
  } */
    }
</style>

